import{_ as a,H as e,f as o,i as l}from"./chunks/framework.Cvt1eIE0.js";const c=JSON.parse('{"title":"提交数据集","description":"","frontmatter":{},"headers":[],"relativePath":"submit.md","filePath":"submit.md"}'),i={name:"submit.md"};function n(s,t,r,d,p,h){return e(),o("div",null,[...t[0]||(t[0]=[l(`<h1 id="提交数据集" tabindex="-1">提交数据集 <a class="header-anchor" href="#提交数据集" aria-label="Permalink to &quot;提交数据集&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">欢迎提交</p><p>欢迎提交数据集信息，我们审核后收录到导航站。</p></div><h2 id="提交须知" tabindex="-1">提交须知 <a class="header-anchor" href="#提交须知" aria-label="Permalink to &quot;提交须知&quot;">​</a></h2><h3 id="收录标准" tabindex="-1">收录标准 <a class="header-anchor" href="#收录标准" aria-label="Permalink to &quot;收录标准&quot;">​</a></h3><ol><li><strong>真实性</strong>: 必须是真实存在的数据集</li><li><strong>可用性</strong>: 有官方链接或申请入口</li><li><strong>完整性</strong>: 提供基础字段信息</li></ol><h3 id="数据集字段" tabindex="-1">数据集字段 <a class="header-anchor" href="#数据集字段" aria-label="Permalink to &quot;数据集字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>数据集名称</td><td>✅</td><td>官方名称</td></tr><tr><td>机构</td><td>✅</td><td>发布机构/公司</td></tr><tr><td>规模</td><td>⭕</td><td>轨迹数/小时/场景数等</td></tr><tr><td>机器人类型</td><td>⭕</td><td>人形/机械臂/移动/四足/仿真</td></tr><tr><td>任务类型</td><td>⭕</td><td>抓取/操作/导航/装配等</td></tr><tr><td>数据模态</td><td>⭕</td><td>视觉/力控/点云/触觉等</td></tr><tr><td>类型</td><td>✅</td><td>开源/闭源/可申请/可采购</td></tr><tr><td>官方链接</td><td>✅</td><td>官网或 GitHub</td></tr><tr><td>论文链接</td><td>⭕</td><td>有则提供</td></tr><tr><td>备注</td><td>⭕</td><td>一句话点评</td></tr></tbody></table><h3 id="类型说明" tabindex="-1">类型说明 <a class="header-anchor" href="#类型说明" aria-label="Permalink to &quot;类型说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>🟢 开源</td><td>可自由下载使用</td></tr><tr><td>🟡 可申请</td><td>需要申请或注册</td></tr><tr><td>🔴 闭源</td><td>不公开获取</td></tr></tbody></table><hr><h2 id="提交表单" tabindex="-1">提交表单 <a class="header-anchor" href="#提交表单" aria-label="Permalink to &quot;提交表单&quot;">​</a></h2><h3 id="方式一-邮件提交" tabindex="-1">方式一：邮件提交 <a class="header-anchor" href="#方式一-邮件提交" aria-label="Permalink to &quot;方式一：邮件提交&quot;">​</a></h3><p>发送邮件至：<strong><a href="mailto:submit@embodiedai-data.com" target="_blank" rel="noreferrer">submit@embodiedai-data.com</a></strong></p><p>邮件格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主题：【数据集提交】数据集名称</span></span>
<span class="line"><span></span></span>
<span class="line"><span>数据集名称：</span></span>
<span class="line"><span>机构：</span></span>
<span class="line"><span>规模：</span></span>
<span class="line"><span>机器人类型：</span></span>
<span class="line"><span>任务类型：</span></span>
<span class="line"><span>数据模态：</span></span>
<span class="line"><span>类型：</span></span>
<span class="line"><span>官方链接：</span></span>
<span class="line"><span>论文链接：</span></span>
<span class="line"><span>备注：</span></span></code></pre></div><h3 id="方式二-github-issues" tabindex="-1">方式二：GitHub Issues <a class="header-anchor" href="#方式二-github-issues" aria-label="Permalink to &quot;方式二：GitHub Issues&quot;">​</a></h3><p>在 <a href="https://github.com/embodiedai-datasets/embodiedai-datasets" target="_blank" rel="noreferrer">GitHub 仓库</a> 提交 Issue。</p><h3 id="方式三-表单提交" tabindex="-1">方式三：表单提交 <a class="header-anchor" href="#方式三-表单提交" aria-label="Permalink to &quot;方式三：表单提交&quot;">​</a></h3><form><div class="form-group"><label for="name">数据集名称 *</label><input type="text" id="name" placeholder="例如：Open X-Embodiment"></div><div class="form-group"><label for="org">机构 *</label><input type="text" id="org" placeholder="例如：Google DeepMind"></div><div class="form-group"><label for="scale">规模</label><input type="text" id="scale" placeholder="例如：100W+ 轨迹"></div><div class="form-group"><label for="robot">机器人类型</label><select id="robot"><option value="">请选择</option><option value="humanoid">人形机器人</option><option value="manipulator">机械臂</option><option value="mobile">移动机器人</option><option value="quadruped">四足机器人</option><option value="simulation">仿真</option><option value="tactile">触觉传感</option><option value="other">其他</option></select></div><div class="form-group"><label for="task">任务类型</label><select id="task"><option value="">请选择</option><option value="grasp">抓取</option><option value="manipulation">操作</option><option value="navigation">导航</option><option value="assembly">装配</option><option value="interaction">交互</option><option value="household">家居</option><option value="other">其他</option></select></div><div class="form-group"><label for="type">数据类型 *</label><select id="type"><option value="">请选择</option><option value="open">开源</option><option value="partial">部分开源</option><option value="apply">可申请</option><option value="closed">闭源</option></select></div><div class="form-group"><label for="link">官方链接 *</label><input type="url" id="link" placeholder="https://..."></div><div class="form-group"><label for="paper">论文链接</label><input type="url" id="paper" placeholder="https://arxiv.org/..."></div><div class="form-group"><label for="note">备注</label><textarea id="note" rows="3" placeholder="一句话点评，适合什么场景..."></textarea></div><div class="form-group"><label for="contact">联系邮箱 *</label><input type="email" id="contact" placeholder="用于后续联系"></div><p><button type="submit">提交</button></p></form><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-提交后多久审核" tabindex="-1">Q: 提交后多久审核？ <a class="header-anchor" href="#q-提交后多久审核" aria-label="Permalink to &quot;Q: 提交后多久审核？&quot;">​</a></h3><p>A: 我们会在 3-5 个工作日内审核并回复。</p><h3 id="q-可以提交闭源数据集吗" tabindex="-1">Q: 可以提交闭源数据集吗？ <a class="header-anchor" href="#q-可以提交闭源数据集吗" aria-label="Permalink to &quot;Q: 可以提交闭源数据集吗？&quot;">​</a></h3><p>A: 可以，只要数据集真实存在且有获取渠道。</p><h3 id="q-可以提交商业数据集吗" tabindex="-1">Q: 可以提交商业数据集吗？ <a class="header-anchor" href="#q-可以提交商业数据集吗" aria-label="Permalink to &quot;Q: 可以提交商业数据集吗？&quot;">​</a></h3><p>A: 可以，只要不侵犯商业机密，我们可以收录公开信息。</p><h3 id="q-如何更新已有数据集信息" tabindex="-1">Q: 如何更新已有数据集信息？ <a class="header-anchor" href="#q-如何更新已有数据集信息" aria-label="Permalink to &quot;Q: 如何更新已有数据集信息？&quot;">​</a></h3><p>A: 通过同样方式联系我们，我们会及时更新。</p><hr><div class="info custom-block"><p class="custom-block-title">免责声明</p><ul><li>本网站仅做信息导航，不提供任何数据集下载</li><li>数据集版权归原机构/作者所有</li><li>如有版权问题，请联系删除</li></ul></div>`,31)])])}const b=a(i,[["render",n]]);export{c as __pageData,b as default};
